🔹 Déclaration de variables
$age = 25
$nom = &quot;Gautier&quot;
$estConnecte = $true
$pi = 3.14
$ville = &quot;Angers&quot;   # typage dynamique

🔹 Structures de contrôle
Condition
if ($age -gt 18) {
    Write-Output &quot;Majeur&quot;
}
else {
    Write-Output &quot;Mineur&quot;
}
Switch
switch ($jour) {
    &quot;lundi&quot; { Write-Output &quot;Début de semaine&quot; }
    default { Write-Output &quot;Autre jour&quot; }
}
Boucles
# for
for ($i = 0; $i -lt 5; $i++) {
    Write-Output $i
}

# while
$i = 0
while ($i -lt 5) {
    Write-Output $i
    $i++
}

# foreach
$fruits = @(&quot;pomme&quot;, &quot;banane&quot;, &quot;orange&quot;)
foreach ($fruit in $fruits) {
    Write-Output $fruit
}

🔹 Fonctions
function Dire-Bonjour {
    param($nom)
    Write-Output &quot;Bonjour $nom&quot;
}

function Addition {
    param(
        [int]$a,
        [int]$b
    )
    return ($a + $b)
}

🔹 Objets &amp; Classes
class Personne {
    [string]$Nom
    [int]$Age

    [void]SePresenter() {
        Write-Output &quot;Je m&#039;appelle $($this.Nom) et j&#039;ai $($this.Age) ans.&quot;
    }
}

# Utilisation
$p = [Personne]::new()
$p.Nom = &quot;Gautier&quot;
$p.Age = 26
$p.SePresenter()

🔹 Listes et Tableaux
# Tableau
$notes = @(10, 15, 20)

# Liste dynamique (ArrayList)
$couleurs = New-Object System.Collections.ArrayList
$couleurs.Add(&quot;Rouge&quot;) | Out-Null
$couleurs.Add(&quot;Bleu&quot;)  | Out-Null

🔹 Null safety
$nom = $null
if ($null -ne $nom) {
    Write-Output $nom.Length
}

🔹 Try / Catch (gestion d’erreurs)
try {
    [int]::Parse(&quot;abc&quot;)
}
catch {
    Write-Output &quot;Erreur : $($_.Exception.Message)&quot;
}

🔹 Script PowerShell (structure minimale)
Write-Output &quot;Hello World!&quot;

# Paramètres possibles
param(
    [string]$Utilisateur,
    [switch]$VerboseMode
)

Write-Output &quot;Utilisateur : $Utilisateur&quot;
